1330   // above codes. And it may be problematic in edge cases. See
1331   // https://github.com/llvm/llvm-project/issues/57861 for an example.
1332   if (Shape.ABI == coro::ABI::Switch && Shape.SwitchLowering.PromiseAlloca) {
1333     AllocaInst *PA = Shape.SwitchLowering.PromiseAlloca;
1334     // If there is memory accessing to promise alloca before CoroBegin;
1335     bool HasAccessingPromiseBeforeCB = llvm::any_of(PA->uses(), [&](Use &U) {
1336       auto *Inst = dyn_cast<Instruction>(U.getUser());
1337       if (!Inst || DT.dominates(Shape.CoroBegin, Inst))
1338         return false;
1339 
1340       if (auto *CI = dyn_cast<CallInst>(Inst)) {
1341         // It is fine if the call wouldn't write to the Promise.
1342         // This is possible for @llvm.coro.id intrinsics, which
1343         // would take the promise as the second argument as a
1344         // marker.
1345         if (CI->onlyReadsMemory() ||
1346             CI->onlyReadsMemory(CI->getArgOperandNo(&U)))
