1370 // Moves the values in the PHIs in SuccBB that correspong to PredBB into a new
1371 // PHI in InsertedBB.
1372 static void movePHIValuesToInsertedBlock(BasicBlock *SuccBB,
1373                                          BasicBlock *InsertedBB,
1374                                          BasicBlock *PredBB,
1375                                          PHINode *UntilPHI = nullptr) {
1376   auto *PN = cast<PHINode>(&SuccBB->front());
1377   do {
1378     int Index = PN->getBasicBlockIndex(InsertedBB);
1379     Value *V = PN->getIncomingValue(Index);
1380     PHINode *InputV = PHINode::Create(
1381         V->getType(), 1, V->getName() + Twine(".") + SuccBB->getName());
1382     InputV->insertBefore(InsertedBB->begin());
1383     InputV->addIncoming(V, PredBB);
1384     PN->setIncomingValue(Index, InputV);
1385     PN = dyn_cast<PHINode>(PN->getNextNode());
1386   } while (PN != UntilPHI);
1387 }
