1389 // Rewrites the PHI Nodes in a cleanuppad.
1390 static void rewritePHIsForCleanupPad(BasicBlock *CleanupPadBB,
1391                                      CleanupPadInst *CleanupPad) {
1392   // For every incoming edge to a CleanupPad we will create a new block holding
1393   // all incoming values in single-value PHI nodes. We will then create another
1394   // block to act as a dispather (as all unwind edges for related EH blocks
1395   // must be the same).
1396   //
1397   // cleanuppad:
1398   //    %2 = phi i32[%0, %catchswitch], [%1, %catch.1]
1399   //    %3 = cleanuppad within none []
1400   //
1401   // It will create:
1402   //
1403   // cleanuppad.corodispatch
1404   //    %2 = phi i8[0, %catchswitch], [1, %catch.1]
1405   //    %3 = cleanuppad within none []
1406   //    switch i8 % 2, label %unreachable
1407   //            [i8 0, label %cleanuppad.from.catchswitch
1408   //             i8 1, label %cleanuppad.from.catch.1]
1409   // cleanuppad.from.catchswitch:
1410   //    %4 = phi i32 [%0, %catchswitch]
1411   //    br %label cleanuppad
1412   // cleanuppad.from.catch.1:
1413   //    %6 = phi i32 [%1, %catch.1]
1414   //    br %label cleanuppad
1415   // cleanuppad:
1416   //    %8 = phi i32 [%4, %cleanuppad.from.catchswitch],
1417   //                 [%6, %cleanuppad.from.catch.1]
1418 
1419   // Unreachable BB, in case switching on an invalid value in the dispatcher.
1420   auto *UnreachBB = BasicBlock::Create(
1421       CleanupPadBB->getContext(), "unreachable", CleanupPadBB->getParent());
1422   IRBuilder<> Builder(UnreachBB);
1423   Builder.CreateUnreachable();
1424 
1425   // Create a new cleanuppad which will be the dispatcher.
1426   auto *NewCleanupPadBB =
1427       BasicBlock::Create(CleanupPadBB->getContext(),
1428                          CleanupPadBB->getName() + Twine(".corodispatch"),
1429                          CleanupPadBB->getParent(), CleanupPadBB);
1430   Builder.SetInsertPoint(NewCleanupPadBB);
1431   auto *SwitchType = Builder.getInt8Ty();
1432   auto *SetDispatchValuePN =
1433       Builder.CreatePHI(SwitchType, pred_size(CleanupPadBB));
1434   CleanupPad->removeFromParent();
1435   CleanupPad->insertAfter(SetDispatchValuePN->getIterator());
1436   auto *SwitchOnDispatch = Builder.CreateSwitch(SetDispatchValuePN, UnreachBB,
1437                                                 pred_size(CleanupPadBB));
1438 
1439   int SwitchIndex = 0;
1440   SmallVector<BasicBlock *, 8> Preds(predecessors(CleanupPadBB));
1441   for (BasicBlock *Pred : Preds) {
1442     // Create a new cleanuppad and move the PHI values to there.
1443     auto *CaseBB = BasicBlock::Create(CleanupPadBB->getContext(),
1444                                       CleanupPadBB->getName() +
1445                                           Twine(".from.") + Pred->getName(),
1446                                       CleanupPadBB->getParent(), CleanupPadBB);
1447     updatePhiNodes(CleanupPadBB, Pred, CaseBB);
1448     CaseBB->setName(CleanupPadBB->getName() + Twine(".from.") +
1449                     Pred->getName());
1450     Builder.SetInsertPoint(CaseBB);
1451     Builder.CreateBr(CleanupPadBB);
1452     movePHIValuesToInsertedBlock(CleanupPadBB, CaseBB, NewCleanupPadBB);
1453 
1454     // Update this Pred to the new unwind point.
1455     setUnwindEdgeTo(Pred->getTerminator(), NewCleanupPadBB);
1456 
1457     // Setup the switch in the dispatcher.
1458     auto *SwitchConstant = ConstantInt::get(SwitchType, SwitchIndex);
1459     SetDispatchValuePN->addIncoming(SwitchConstant, Pred);
1460     SwitchOnDispatch->addCase(SwitchConstant, CaseBB);
1461     SwitchIndex++;
1462   }
1463 }
