1465 static void cleanupSinglePredPHIs(Function &F) {
1466   SmallVector<PHINode *, 32> Worklist;
1467   for (auto &BB : F) {
1468     for (auto &Phi : BB.phis()) {
1469       if (Phi.getNumIncomingValues() == 1) {
1470         Worklist.push_back(&Phi);
1471       } else
1472         break;
1473     }
1474   }
1475   while (!Worklist.empty()) {
1476     auto *Phi = Worklist.pop_back_val();
1477     auto *OriginalValue = Phi->getIncomingValue(0);
1478     Phi->replaceAllUsesWith(OriginalValue);
1479   }
1480 }
