1482 static void rewritePHIs(BasicBlock &BB) {
1483   // For every incoming edge we will create a block holding all
1484   // incoming values in a single PHI nodes.
1485   //
1486   // loop:
1487   //    %n.val = phi i32[%n, %entry], [%inc, %loop]
1488   //
1489   // It will create:
1490   //
1491   // loop.from.entry:
1492   //    %n.loop.pre = phi i32 [%n, %entry]
1493   //    br %label loop
1494   // loop.from.loop:
1495   //    %inc.loop.pre = phi i32 [%inc, %loop]
1496   //    br %label loop
1497   //
1498   // After this rewrite, further analysis will ignore any phi nodes with more
1499   // than one incoming edge.
1500 
1501   // TODO: Simplify PHINodes in the basic block to remove duplicate
1502   // predecessors.
1503 
1504   // Special case for CleanupPad: all EH blocks must have the same unwind edge
1505   // so we need to create an additional "dispatcher" block.
1506   if (!BB.empty()) {
1507     if (auto *CleanupPad =
1508             dyn_cast_or_null<CleanupPadInst>(BB.getFirstNonPHIIt())) {
1509       SmallVector<BasicBlock *, 8> Preds(predecessors(&BB));
1510       for (BasicBlock *Pred : Preds) {
1511         if (CatchSwitchInst *CS =
1512                 dyn_cast<CatchSwitchInst>(Pred->getTerminator())) {
1513           // CleanupPad with a CatchSwitch predecessor: therefore this is an
1514           // unwind destination that needs to be handle specially.
1515           assert(CS->getUnwindDest() == &BB);
1516           (void)CS;
1517           rewritePHIsForCleanupPad(&BB, CleanupPad);
1518           return;
1519         }
1520       }
1521     }
1522   }
1523 
1524   LandingPadInst *LandingPad = nullptr;
1525   PHINode *ReplPHI = nullptr;
1526   if (!BB.empty()) {
1527     if ((LandingPad =
1528              dyn_cast_or_null<LandingPadInst>(BB.getFirstNonPHIIt()))) {
1529       // ehAwareSplitEdge will clone the LandingPad in all the edge blocks.
1530       // We replace the original landing pad with a PHINode that will collect the
1531       // results from all of them.
1532       ReplPHI = PHINode::Create(LandingPad->getType(), 1, "");
1533       ReplPHI->insertBefore(LandingPad->getIterator());
1534       ReplPHI->takeName(LandingPad);
1535       LandingPad->replaceAllUsesWith(ReplPHI);
1536       // We will erase the original landing pad at the end of this function after
1537       // ehAwareSplitEdge cloned it in the transition blocks.
1538     }
1539   }
1540 
1541   SmallVector<BasicBlock *, 8> Preds(predecessors(&BB));
1542   for (BasicBlock *Pred : Preds) {
1543     auto *IncomingBB = ehAwareSplitEdge(Pred, &BB, LandingPad, ReplPHI);
1544     IncomingBB->setName(BB.getName() + Twine(".from.") + Pred->getName());
1545 
1546     // Stop the moving of values at ReplPHI, as this is either null or the PHI
1547     // that replaced the landing pad.
1548     movePHIValuesToInsertedBlock(&BB, IncomingBB, Pred, ReplPHI);
1549   }
