1081 static void insertSpills(const FrameDataInfo &FrameData, coro::Shape &Shape) {
1082   LLVMContext &C = Shape.CoroBegin->getContext();
1083   Function *F = Shape.CoroBegin->getFunction();
1084   IRBuilder<> Builder(C);
1085   StructType *FrameTy = Shape.FrameTy;
1086   DominatorTree DT(*F);
1087   SmallDenseMap<Argument *, AllocaInst *, 4> ArgToAllocaMap;
1088 
1089   MDBuilder MDB(C);
1090   // Create a TBAA tag for accesses to certain coroutine frame slots, so that
1091   // subsequent alias analysis will understand they do not intersect with
1092   // user memory.
1093   // We do this only if a suitable TBAA root already exists in the module.
1094   MDNode *TBAATag = nullptr;
1095   if (auto *CppTBAAStr = MDString::getIfExists(C, "Simple C++ TBAA")) {
1096     auto *TBAARoot = MDNode::getIfExists(C, CppTBAAStr);
1097     // Create a "fake" scalar type; all other types defined in the source
1098     // language will be assumed non-aliasing with this type.
1099     MDNode *Scalar = MDB.createTBAAScalarTypeNode(
1100         (F->getName() + ".Frame Slot").str(), TBAARoot);
1101     TBAATag = MDB.createTBAAStructTagNode(Scalar, Scalar, 0);
1102   }
1103   for (auto const &E : FrameData.Spills) {
1104     Value *Def = E.first;
1105     Type *ByValTy = extractByvalIfArgument(Def);
1106 
1107     Builder.SetInsertPoint(coro::getSpillInsertionPt(Shape, Def, DT));
1108     createStoreIntoFrame(Builder, Def, ByValTy, Shape, FrameData);
1109 
1110     BasicBlock *CurrentBlock = nullptr;
1111     Value *CurrentReload = nullptr;
1112     for (auto *U : E.second) {
1113       // If we have not seen the use block, create a load instruction to reload
1114       // the spilled value from the coroutine frame. Populates the Value pointer
1115       // reference provided with the frame GEP.
1116       if (CurrentBlock != U->getParent()) {
1117         CurrentBlock = U->getParent();
1118         Builder.SetInsertPoint(CurrentBlock,
1119                                CurrentBlock->getFirstInsertionPt());
1120 
1121         auto *GEP = createGEPToFramePointer(FrameData, Builder, Shape, E.first);
1122         GEP->setName(E.first->getName() + Twine(".reload.addr"));
1123         if (ByValTy) {
1124           CurrentReload = GEP;
1125         } else {
1126           auto SpillAlignment = Align(FrameData.getAlign(Def));
1127           auto *LI = Builder.CreateAlignedLoad(
1128               FrameTy->getElementType(FrameData.getFieldIndex(E.first)), GEP,
1129               SpillAlignment, E.first->getName() + Twine(".reload"));
1130           if (TBAATag)
1131             LI->setMetadata(LLVMContext::MD_tbaa, TBAATag);
1132           CurrentReload = LI;
1133         }
1134 
1135         TinyPtrVector<DbgVariableRecord *> DVRs = findDVRDeclares(Def);
1136         // Try best to find dbg.declare. If the spill is a temp, there may not
