 996 /// Store Def into the coroutine frame.
 997 static void createStoreIntoFrame(IRBuilder<> &Builder, Value *Def,
 998                                  Type *ByValTy, const coro::Shape &Shape,
 999                                  const FrameDataInfo &FrameData) {
1000   auto Index = FrameData.getFieldIndex(Def);
1001   auto *G = Builder.CreateConstInBoundsGEP2_32(
1002       Shape.FrameTy, Shape.FramePtr, 0, Index,
1003       Def->getName() + Twine(".spill.addr"));
1004   auto SpillAlignment = Align(FrameData.getAlign(Def));
1005 
1006   // For byval arguments, store the pointed-to value in the frame.
1007   if (ByValTy)
1008     Builder.CreateAlignedStore(Builder.CreateLoad(ByValTy, Def), G,
1009                                SpillAlignment);
1010   else
1011     Builder.CreateAlignedStore(Def, G, SpillAlignment);
1012 }
