1014 /// Returns a GEP into the coroutine frame at the offset where Orig is located.
1015 static Value *createGEPToFramePointer(const FrameDataInfo &FrameData,
1016                                       IRBuilder<> &Builder, coro::Shape &Shape,
1017                                       Value *Orig) {
1018   LLVMContext &Ctx = Shape.CoroBegin->getContext();
1019   FieldIDType Index = FrameData.getFieldIndex(Orig);
1020   SmallVector<Value *, 3> Indices = {
1021       ConstantInt::get(Type::getInt32Ty(Ctx), 0),
1022       ConstantInt::get(Type::getInt32Ty(Ctx), Index),
1023   };
1024 
1025   // If Orig is an array alloca, preserve the original type by adding an extra
1026   // zero offset.
1027   if (auto *AI = dyn_cast<AllocaInst>(Orig)) {
1028     if (ConstantInt *CI = dyn_cast<ConstantInt>(AI->getArraySize())) {
1029       auto Count = CI->getValue().getZExtValue();
1030       if (Count > 1)
1031         Indices.push_back(ConstantInt::get(Type::getInt32Ty(Ctx), 0));
1032     } else {
1033       report_fatal_error("Coroutines cannot handle non static allocas yet");
1034     }
1035   }
1036 
1037   auto *GEP = Builder.CreateInBoundsGEP(Shape.FrameTy, Shape.FramePtr, Indices);
1038   if (auto *AI = dyn_cast<AllocaInst>(Orig)) {
1039     if (FrameData.getDynamicAlign(Orig) != 0) {
1040       assert(FrameData.getDynamicAlign(Orig) == AI->getAlign().value());
1041       auto *M = AI->getModule();
1042       auto *IntPtrTy = M->getDataLayout().getIntPtrType(AI->getType());
1043       auto *PtrValue = Builder.CreatePtrToInt(GEP, IntPtrTy);
1044       auto *AlignMask = ConstantInt::get(IntPtrTy, AI->getAlign().value() - 1);
1045       PtrValue = Builder.CreateAdd(PtrValue, AlignMask);
1046       PtrValue = Builder.CreateAnd(PtrValue, Builder.CreateNot(AlignMask));
1047       return Builder.CreateIntToPtr(PtrValue, AI->getType());
1048     }
1049     // If the type of GEP is not equal to the type of AllocaInst, it implies
1050     // that the AllocaInst may be reused in the Frame slot of other AllocaInst.
1051     // Note: If the strategy dealing with alignment changes, this cast must be
1052     // refined
1053     if (GEP->getType() != Orig->getType())
1054       GEP = Builder.CreateAddrSpaceCast(GEP, Orig->getType(),
1055                                         Orig->getName() + Twine(".cast"));
1056   }
1057   return GEP;
1058 }
